# Ribbons

OGL WebGL spring-based ribbon effect that follows mouse and touch movements with fluid multi-color trails. Supports fade, shader wave distortion, and multiple concurrent ribbon colors.

## Use when
- Adding a fluid cursor trail that enhances brand personality on a dark landing page.
- Creating an interactive demo area where cursor movement leaves colorful ribbons.
- Decorating a hero section with ambient ribbon motion.

## Stack
- Framework: react
- Libraries: ogl

## Install
```bash
npm install ogl
```

## Component — ribbons.tsx
```tsx
import React, { useEffect, useRef } from 'react';
import { Renderer, Transform, Vec3, Color, Polyline } from 'ogl';

interface RibbonsProps {
  colors?: string[];
  baseSpring?: number;
  baseFriction?: number;
  baseThickness?: number;
  offsetFactor?: number;
  maxAge?: number;
  pointCount?: number;
  speedMultiplier?: number;
  enableFade?: boolean;
  enableShaderEffect?: boolean;
  effectAmplitude?: number;
  backgroundColor?: number[];
}

export const Ribbons: React.FC<RibbonsProps> = ({
  colors = ['#ff9346', '#7cff67', '#ffee51', '#5227FF'],
  baseSpring = 0.03,
  baseFriction = 0.9,
  baseThickness = 30,
  offsetFactor = 0.05,
  maxAge = 500,
  pointCount = 50,
  speedMultiplier = 0.6,
  enableFade = false,
  enableShaderEffect = false,
  effectAmplitude = 2,
  backgroundColor = [0, 0, 0, 0]
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const renderer = new Renderer({ dpr: window.devicePixelRatio || 2, alpha: true });
    const gl = renderer.gl;
    if (Array.isArray(backgroundColor) && backgroundColor.length === 4) {
      gl.clearColor(backgroundColor[0], backgroundColor[1], backgroundColor[2], backgroundColor[3]);
    } else { gl.clearColor(0, 0, 0, 0); }

    gl.canvas.style.position = 'absolute';
    gl.canvas.style.top = '0'; gl.canvas.style.left = '0';
    gl.canvas.style.width = '100%'; gl.canvas.style.height = '100%';
    container.appendChild(gl.canvas);

    const scene = new Transform();
    const lines: { spring: number; friction: number; mouseVelocity: Vec3; mouseOffset: Vec3; points: Vec3[]; polyline: Polyline; }[] = [];

    const vertex = `
      precision highp float;
      attribute vec3 position; attribute vec3 next; attribute vec3 prev;
      attribute vec2 uv; attribute float side;
      uniform vec2 uResolution; uniform float uDPR; uniform float uThickness;
      uniform float uTime; uniform float uEnableShaderEffect; uniform float uEffectAmplitude;
      varying vec2 vUV;
      vec4 getPosition() {
          vec4 current = vec4(position, 1.0);
          vec2 aspect = vec2(uResolution.x / uResolution.y, 1.0);
          vec2 nextScreen = next.xy * aspect; vec2 prevScreen = prev.xy * aspect;
          vec2 tangent = normalize(nextScreen - prevScreen);
          vec2 normal = vec2(-tangent.y, tangent.x);
          normal /= aspect;
          normal *= mix(1.0, 0.1, pow(abs(uv.y - 0.5) * 2.0, 2.0));
          float dist = length(nextScreen - prevScreen);
          normal *= smoothstep(0.0, 0.02, dist);
          float pixelWidthRatio = 1.0 / (uResolution.y / uDPR);
          float pixelWidth = current.w * pixelWidthRatio;
          normal *= pixelWidth * uThickness;
          current.xy -= normal * side;
          if(uEnableShaderEffect > 0.5) { current.xy += normal * sin(uTime + current.x * 10.0) * uEffectAmplitude; }
          return current;
      }
      void main() { vUV = uv; gl_Position = getPosition(); }
    `;

    const fragment = `
      precision highp float;
      uniform vec3 uColor; uniform float uOpacity; uniform float uEnableFade;
      varying vec2 vUV;
      void main() {
          float fadeFactor = 1.0;
          if(uEnableFade > 0.5) { fadeFactor = 1.0 - smoothstep(0.0, 1.0, vUV.y); }
          gl_FragColor = vec4(uColor, uOpacity * fadeFactor);
      }
    `;

    function resize() {
      if (!container) return;
      renderer.setSize(container.clientWidth, container.clientHeight);
      lines.forEach(line => line.polyline.resize());
    }
    window.addEventListener('resize', resize);

    const center = (colors.length - 1) / 2;
    colors.forEach((color, index) => {
      const spring = baseSpring + (Math.random() - 0.5) * 0.05;
      const friction = baseFriction + (Math.random() - 0.5) * 0.05;
      const thickness = baseThickness + (Math.random() - 0.5) * 3;
      const mouseOffset = new Vec3((index - center) * offsetFactor + (Math.random() - 0.5) * 0.01, (Math.random() - 0.5) * 0.1, 0);
      const points: Vec3[] = [];
      for (let i = 0; i < pointCount; i++) points.push(new Vec3());
      const line = { spring, friction, mouseVelocity: new Vec3(), mouseOffset, points, polyline: {} as Polyline };
      line.polyline = new Polyline(gl, { points, vertex, fragment, uniforms: { uColor: { value: new Color(color) }, uThickness: { value: thickness }, uOpacity: { value: 1.0 }, uTime: { value: 0.0 }, uEnableShaderEffect: { value: enableShaderEffect ? 1.0 : 0.0 }, uEffectAmplitude: { value: effectAmplitude }, uEnableFade: { value: enableFade ? 1.0 : 0.0 } } });
      line.polyline.mesh.setParent(scene);
      lines.push(line);
    });

    resize();
    const mouse = new Vec3();
    function updateMouse(e: MouseEvent | TouchEvent) {
      if (!container) return;
      const rect = container.getBoundingClientRect();
      let x: number, y: number;
      if ('changedTouches' in e && e.changedTouches.length) { x = e.changedTouches[0].clientX - rect.left; y = e.changedTouches[0].clientY - rect.top; }
      else if (e instanceof MouseEvent) { x = e.clientX - rect.left; y = e.clientY - rect.top; }
      else { x = 0; y = 0; }
      mouse.set((x / container.clientWidth) * 2 - 1, (y / container.clientHeight) * -2 + 1, 0);
    }
    container.addEventListener('mousemove', updateMouse);
    container.addEventListener('touchstart', updateMouse, { passive: false });
    container.addEventListener('touchmove', updateMouse, { passive: false });

    let frameId: number;
    let lastTime = performance.now();
    function update() {
      frameId = requestAnimationFrame(update);
      const currentTime = performance.now();
      const dt = currentTime - lastTime;
      lastTime = currentTime;
      lines.forEach(line => {
        const tmp = new Vec3();
        tmp.copy(mouse).add(line.mouseOffset).sub(line.points[0]).multiply(line.spring);
        line.mouseVelocity.add(tmp).multiply(line.friction);
        line.points[0].add(line.mouseVelocity);
        for (let i = 1; i < line.points.length; i++) {
          if (isFinite(maxAge) && maxAge > 0) {
            const segmentDelay = maxAge / (line.points.length - 1);
            const alpha = Math.min(1, (dt * speedMultiplier) / segmentDelay);
            line.points[i].lerp(line.points[i - 1], alpha);
          } else { line.points[i].lerp(line.points[i - 1], 0.9); }
        }
        if (line.polyline.mesh.program.uniforms.uTime) line.polyline.mesh.program.uniforms.uTime.value = currentTime * 0.001;
        line.polyline.updateGeometry();
      });
      renderer.render({ scene });
    }
    update();

    return () => {
      window.removeEventListener('resize', resize);
      container.removeEventListener('mousemove', updateMouse);
      container.removeEventListener('touchstart', updateMouse);
      container.removeEventListener('touchmove', updateMouse);
      cancelAnimationFrame(frameId);
      if (gl.canvas && gl.canvas.parentNode === container) container.removeChild(gl.canvas);
    };
  }, [colors, baseSpring, baseFriction, baseThickness, offsetFactor, maxAge, pointCount, speedMultiplier, enableFade, enableShaderEffect, effectAmplitude, backgroundColor]);

  return <div ref={containerRef} className="relative w-full h-full cursor-none" />;
};

export default Ribbons;
```

## Demo
```tsx
import React, { useState } from 'react';
import { Ribbons } from './Component';
import { motion, AnimatePresence } from 'framer-motion';

export default function App() {
  const [isHovered, setIsHovered] = useState(false);
  return (
    <div className="min-h-screen bg-[#F9F9F9] flex items-center justify-center p-20 font-sans">
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.6 }} className="relative w-full max-w-4xl aspect-video bg-white rounded-[2rem] shadow-[0_40px_80px_rgba(0,0,0,0.05)] overflow-hidden" onMouseEnter={() => setIsHovered(true)} onMouseLeave={() => setIsHovered(false)}>
        <div className="absolute inset-0 z-0">
          <Ribbons baseThickness={40} colors={['#1A1A1B']} speedMultiplier={0.5} maxAge={600} enableFade={true} enableShaderEffect={true} effectAmplitude={1.5} backgroundColor={[0,0,0,0]} />
        </div>
        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center pointer-events-none p-12 text-center">
          <motion.h1 initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.4, duration: 0.8 }} className="text-[2.5rem] font-medium tracking-tight text-[#1A1A1B] mb-2">Fluid Motion</motion.h1>
          <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.6, duration: 0.8 }} className="text-[#888888] font-normal">A Minimalist WebGL Ribbon Showcase</motion.p>
        </div>
      </motion.div>
    </div>
  );
}
```
